import { Component } from 'react';
import { AlertCircle, RefreshCw, Home } from 'lucide-react';

class ErrorBoundary extends Component {
    constructor(props) {
        super(props);
        this.state = { hasError: false, error: null, errorInfo: null };
    }

    static getDerivedStateFromError(error) {
        return { hasError: true };
    }

    componentDidCatch(error, errorInfo) {
        // Safely log error
        const errorMessage = error?.message || error?.toString() || 'Unknown error';
        const errorStack = error?.stack || 'No stack trace';
        
        console.error('Error caught by boundary:', errorMessage);
        console.error('Error stack:', errorStack);
        
        this.setState({
            error: { message: errorMessage, stack: errorStack },
            errorInfo
        });
    }

    handleReset = () => {
        this.setState({ hasError: false, error: null, errorInfo: null });
        window.location.href = '/';
    };

    handleReload = () => {
        window.location.reload();
    };

    render() {
        if (this.state.hasError) {
            return (
                <div className="min-h-screen bg-background flex items-center justify-center p-6">
                    <div className="max-w-md w-full">
                        <div className="bg-surface border border-border-light rounded-2xl p-8 text-center">
                            <div className="w-16 h-16 bg-danger/10 rounded-full flex items-center justify-center mx-auto mb-4">
                                <AlertCircle size={32} className="text-danger" />
                            </div>
                            
                            <h1 className="text-2xl font-bold text-text-primary mb-2">
                                Something went wrong
                            </h1>
                            
                            <p className="text-text-secondary mb-6">
                                We're sorry, but something unexpected happened. Please try refreshing the page or returning to the home page.
                            </p>

                            {import.meta.env.DEV && this.state.error && (
                                <div className="bg-danger/5 border border-danger/20 rounded-lg p-4 mb-6 text-left">
                                    <p className="text-xs font-mono text-danger break-all">
                                        {this.state.error.message || 'Unknown error'}
                                    </p>
                                </div>
                            )}

                            <div className="flex flex-col sm:flex-row gap-3 justify-center">
                                <button
                                    onClick={this.handleReload}
                                    className="btn btn-primary flex items-center justify-center gap-2"
                                >
                                    <RefreshCw size={16} />
                                    Reload Page
                                </button>
                                <button
                                    onClick={this.handleReset}
                                    className="btn btn-secondary flex items-center justify-center gap-2"
                                >
                                    <Home size={16} />
                                    Go Home
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            );
        }

        return this.props.children;
    }
}

export default ErrorBoundary;

import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { ArrowLeft } from 'lucide-react';

/**
 * PageHeader — Reusable premium header for all dashboard pages.
 * Shows a back button (history or fixed path), page title, badge and optional actions.
 */
const PageHeader = ({
    title,
    subtitle,
    badge,
    backTo,              // Optional: override back navigation path
    backLabel = 'Back',
    actions,             // Optional: JSX slot for action buttons
    className = '',
}) => {
    const navigate = useNavigate();
    const location = useLocation();

    const handleBack = () => {
        if (backTo) {
            navigate(backTo);
        } else if (window.history.length > 1) {
            navigate(-1);
        } else {
            navigate('/app');
        }
    };

    return (
        <div className={`page-header flex flex-col gap-1 ${className}`}>
            {/* Back navigation */}
            <button
                onClick={handleBack}
                className="inline-flex items-center gap-1.5 text-sm font-medium text-text-secondary hover:text-primary transition-colors w-fit mb-3 group"
            >
                <ArrowLeft
                    size={15}
                    className="group-hover:-translate-x-0.5 transition-transform"
                />
                {backLabel}
            </button>

            {/* Title row */}
            <div className="flex items-start justify-between gap-4">
                <div className="flex items-center gap-3 flex-wrap">
                    <h1 className="text-2xl font-extrabold text-text-primary tracking-tight leading-none">
                        {title}
                    </h1>
                    {badge && (
                        <span className="inline-flex items-center px-2.5 py-1 rounded-full text-[11px] font-bold bg-primary/10 text-primary border border-primary/20">
                            {badge}
                        </span>
                    )}
                </div>

                {actions && (
                    <div className="flex items-center gap-2 shrink-0">
                        {actions}
                    </div>
                )}
            </div>

            {/* Subtitle */}
            {subtitle && (
                <p className="text-sm text-text-secondary mt-1 leading-relaxed">
                    {subtitle}
                </p>
            )}
        </div>
    );
};

export default PageHeader;

