import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import {
    createUserWithEmailAndPassword,
    signInWithEmailAndPassword,
    signOut,
    onAuthStateChanged
} from 'firebase/auth';
import { auth, db } from '../services/firebase';
import { doc, getDoc, setDoc, updateDoc } from 'firebase/firestore';
import { hasPermission as checkPermission } from '../services/permissions';

const AuthContext = createContext();


export function AuthProvider({ children }) {
    const [currentUser, setCurrentUser] = useState(null);
    const [userData, setUserData] = useState(null);
    const [loading, setLoading] = useState(true);

    // Permission checker bound to current user role
    const hasPermission = useCallback((action) => {
        if (!userData?.role) return false;
        return checkPermission(userData.role, action);
    }, [userData]);

    // Sign up and create user document in Firestore
    async function signup(email, password, role, name, extraFields = {}) {
        try {
            const userCredential = await createUserWithEmailAndPassword(auth, email, password);
            const user = userCredential.user;

            // Create their profile in firestore with pending approval status
            try {
                await setDoc(doc(db, 'users', user.uid), {
                    uid: user.uid,
                    email: user.email,
                    name: name,
                    role: role,
                    kycStatus: 'pending',
                    approvalStatus: 'pending',
                    createdAt: new Date().toISOString(),
                    updatedAt: new Date().toISOString(),
                    ...extraFields, // Role-specific fields (barNumber, licenseNumber, etc.)
                });
            } catch (firestoreError) {
                console.error('Firestore error:', firestoreError.message || 'Unknown error');
                console.log('User authenticated but Firestore document creation failed. This can be fixed later.');
            }

            return user;
        } catch (error) {
            console.error('Signup error:', error.message || 'Unknown error');

            if (error.code === 'auth/operation-not-allowed') {
                throw new Error('Email/password authentication is not enabled. Please contact support.');
            }

            if (error.code === 'auth/configuration-not-found') {
                throw new Error('Firebase is not properly configured. Please contact support.');
            }

            throw error;
        }
    }

    // Log in
    function login(email, password) {
        return signInWithEmailAndPassword(auth, email, password);
    }

    // Log out
    function logout() {
        return signOut(auth);
    }

    useEffect(() => {
        // Listen for auth state changes
        const unsubscribe = onAuthStateChanged(auth, async (user) => {
            setCurrentUser(user);

            if (user) {
                try {
                    // Fetch additional user role data from firestore
                    const docRef = doc(db, 'users', user.uid);
                    const docSnap = await getDoc(docRef);
                    if (docSnap.exists()) {
                        const data = docSnap.data();

                        // If user doesn't have approvalStatus, add it as 'approved' for backward compatibility
                        if (!data.approvalStatus) {
                            try {
                                await updateDoc(docRef, {
                                    approvalStatus: 'approved',
                                    updatedAt: new Date().toISOString()
                                });
                                data.approvalStatus = 'approved';
                                console.log('Added approvalStatus to user');
                            } catch (updateError) {
                                console.error('Could not update approvalStatus:', updateError.message);
                                // Set it locally anyway for this session
                                data.approvalStatus = 'approved';
                            }
                        }

                        setUserData(data);
                    } else {
                        // User exists in Auth but not in Firestore
                        // This can happen if Firestore wasn't set up during signup
                        console.log('User authenticated but no Firestore document found. Creating one now...');

                        // Create a basic user document
                        try {
                            await setDoc(docRef, {
                                uid: user.uid,
                                email: user.email,
                                name: user.displayName || 'User',
                                role: 'investor', // default role
                                kycStatus: 'pending',
                                approvalStatus: 'pending',
                                createdAt: new Date().toISOString(),
                                updatedAt: new Date().toISOString()
                            });

                            // Fetch the newly created document
                            const newDocSnap = await getDoc(docRef);
                            if (newDocSnap.exists()) {
                                setUserData(newDocSnap.data());
                            }
                        } catch (createError) {
                            console.log('Could not create Firestore document. Firestore may not be configured yet.');
                            // Set minimal user data from auth
                            setUserData({
                                uid: user.uid,
                                email: user.email,
                                role: 'investor'
                            });
                        }
                    }
                } catch (error) {
                    console.log('Firestore not configured yet. User can still authenticate.');
                    // Set minimal user data from auth
                    setUserData({
                        uid: user.uid,
                        email: user.email,
                        role: 'investor'
                    });
                }
            } else {
                setUserData(null);
            }

            setLoading(false);
        });

        return unsubscribe;
    }, []);

    const value = {
        currentUser,
        userData,
        loading,
        signup,
        login,
        logout,
        hasPermission
    };

    return (
        <AuthContext.Provider value={value}>
            {!loading && children}
        </AuthContext.Provider>
    );
}

export function useAuth() {
    return useContext(AuthContext);
}

import React, { createContext, useContext, useEffect, useState } from 'react';

const ThemeContext = createContext();

export function ThemeProvider({ children }) {
    // Check local storage or system preference on initial load
    const [isDarkMode, setIsDarkMode] = useState(() => {
        const savedTheme = localStorage.getItem('theme');
        if (savedTheme) {
            return savedTheme === 'dark';
        }
        return window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
    });

    useEffect(() => {
        const root = window.document.documentElement;
        if (isDarkMode) {
            root.classList.add('dark');
            localStorage.setItem('theme', 'dark');
        } else {
            root.classList.remove('dark');
            localStorage.setItem('theme', 'light');
        }
    }, [isDarkMode]);

    const toggleTheme = () => {
        setIsDarkMode(prev => !prev);
    };

    return (
        <ThemeContext.Provider value={{ isDarkMode, toggleTheme }}>
            {children}
        </ThemeContext.Provider>
    );
}

export function useTheme() {
    return useContext(ThemeContext);
}

import React, { useState, useEffect } from 'react';
import {
  Users, Building, Briefcase, DollarSign, ShieldCheck, AlertTriangle,
  Search, Filter, MoreVertical, ChevronDown, Eye, Settings,
  Download, RefreshCw, Loader2, CheckCircle2, XCircle, Clock, TrendingUp,
  Bell, Activity, FileText, UserCheck, UserX, Mail
} from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';
import { collection, getDocs, doc, updateDoc, query, where, orderBy } from 'firebase/firestore';
import { db } from '../services/firebase';

const Admin = () => {
  const { userData } = useAuth();
  const navigate = useNavigate();

  const [activeTab, setActiveTab] = useState('pending');
  const [users, setUsers] = useState([]);
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [actionLoading, setActionLoading] = useState(null); // Track which user action is loading
  const [stats, setStats] = useState({
    totalUsers: 0,
    pendingApprovals: 0,
    activeListings: 0,
    totalRevenue: '$0'
  });

  useEffect(() => {
    // Redirect non-admins
    if (userData && userData.role !== 'admin') {
      navigate('/app');
    }
  }, [userData, navigate]);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      setLoading(true);

      // Fetch all users
      const usersSnapshot = await getDocs(collection(db, 'users'));
      const usersData = usersSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setUsers(usersData);

      // Fetch properties
      const propsSnapshot = await getDocs(collection(db, 'properties'));
      const propsData = propsSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setProperties(propsData);

      // Calculate stats
      const pendingCount = usersData.filter(u => u.approvalStatus === 'pending').length;
      const activeListings = propsData.filter(p => p.status === 'approved').length;

      setStats({
        totalUsers: usersData.length,
        pendingApprovals: pendingCount,
        activeListings,
        totalRevenue: '$24,800'
      });

    } catch (error) {
      console.error('Admin data load error:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleApproveUser = async (userId) => {
    try {
      setActionLoading(userId + '-approve');
      await updateDoc(doc(db, 'users', userId), {
        approvalStatus: 'approved',
        approvedAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
      });

      // Reload data
      await loadData();
    } catch (error) {
      console.error('Approve error:', error);
      alert('Error approving user: ' + (error.message || 'Please try again.'));
    } finally {
      setActionLoading(null);
    }
  };

  const handleRejectUser = async (userId) => {
    const reason = prompt('Enter rejection reason (optional):');

    try {
      setActionLoading(userId + '-reject');
      await updateDoc(doc(db, 'users', userId), {
        approvalStatus: 'rejected',
        rejectedAt: new Date().toISOString(),
        rejectionReason: reason || 'Not specified',
        updatedAt: new Date().toISOString()
      });

      // Reload data
      await loadData();
    } catch (error) {
      console.error('Reject error:', error);
      alert('Error rejecting user: ' + (error.message || 'Please try again.'));
    } finally {
      setActionLoading(null);
    }
  };

  const filteredUsers = users.filter(u => {
    const matchesSearch =
      u.email?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      u.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      u.role?.toLowerCase().includes(searchQuery.toLowerCase());

    const matchesTab =
      activeTab === 'all' ? true :
        activeTab === 'pending' ? u.approvalStatus === 'pending' :
          activeTab === 'approved' ? u.approvalStatus === 'approved' :
            activeTab === 'rejected' ? u.approvalStatus === 'rejected' :
              true;

    return matchesSearch && matchesTab;
  });

  const ROLE_COLORS = {
    investor: 'bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300',
    developer: 'bg-purple-50 dark:bg-purple-900/20 text-purple-700 dark:text-purple-300',
    owner: 'bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-300',
    attorney: 'bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-300',
    property_manager: 'bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300',
    admin: 'bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-300',
  };

  const STATUS_COLORS = {
    pending: 'bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-300',
    approved: 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300',
    rejected: 'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300',
  };

  if (loading) {
    return (
      <div className="h-[calc(100vh-73px)] flex items-center justify-center bg-gradient-to-br from-gray-50 to-gray-100 dark:from-gray-900 dark:to-gray-800">
        <Loader2 className="w-12 h-12 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="h-[calc(100vh-73px)] overflow-y-auto bg-gradient-to-br from-gray-50 via-red-50/20 to-orange-50/30 dark:from-gray-900 dark:via-gray-900 dark:to-gray-800">
      <div className="p-6 lg:p-8 max-w-[1800px] mx-auto">

        {/* Header */}
        <div className="mb-8">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h1 className="text-4xl font-bold text-text-primary mb-2">Admin Console</h1>
              <p className="text-text-secondary text-lg">
                Platform-wide controls, user approvals and system monitoring
              </p>
            </div>
            <div className="flex items-center gap-3">
              <button
                className="px-6 py-3 rounded-2xl border-2 border-border-light bg-white hover:bg-gray-50 text-text-primary font-semibold transition-all hover:shadow-lg flex items-center gap-2"
                onClick={loadData}
              >
                <RefreshCw size={18} />
                Refresh
              </button>
              <button
                className="px-6 py-3 rounded-2xl bg-gradient-to-r from-primary to-green-600 hover:from-green-600 hover:to-primary text-white font-semibold transition-all hover:shadow-xl hover:scale-105 flex items-center gap-2"
              >
                <Download size={18} />
                Export Data
              </button>
            </div>
          </div>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <div className="bg-white dark:bg-gray-800 rounded-[32px] p-8 border-2 border-gray-100 dark:border-gray-700 hover:shadow-xl transition-all">
            <div className="flex items-center justify-between mb-4">
              <div className="w-14 h-14 rounded-2xl bg-blue-50 dark:bg-blue-900/20 flex items-center justify-center">
                <Users size={28} className="text-blue-600 dark:text-blue-400" />
              </div>
              <span className="text-xs font-bold text-success flex items-center gap-1">
                <TrendingUp size={12} />
                +12%
              </span>
            </div>
            <h3 className="text-4xl font-bold text-text-primary mb-2">{stats.totalUsers}</h3>
            <p className="text-sm text-text-secondary">Total Users</p>
          </div>

          <div className="bg-gradient-to-br from-amber-400 to-amber-600 rounded-[32px] p-8 text-white hover:shadow-2xl transition-all relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16"></div>
            <div className="relative z-10">
              <div className="flex items-center justify-between mb-4">
                <div className="w-14 h-14 rounded-2xl bg-white/20 backdrop-blur-sm flex items-center justify-center">
                  <Clock size={28} />
                </div>
                {stats.pendingApprovals > 0 && (
                  <span className="px-3 py-1 rounded-full bg-white/30 backdrop-blur-sm text-xs font-bold animate-pulse">
                    Action Required
                  </span>
                )}
              </div>
              <h3 className="text-4xl font-bold mb-2">{stats.pendingApprovals}</h3>
              <p className="text-sm text-white/90">Pending Approvals</p>
            </div>
          </div>

          <div className="bg-white dark:bg-gray-800 rounded-[32px] p-8 border-2 border-gray-100 dark:border-gray-700 hover:shadow-xl transition-all">
            <div className="flex items-center justify-between mb-4">
              <div className="w-14 h-14 rounded-2xl bg-green-50 dark:bg-green-900/20 flex items-center justify-center">
                <Building size={28} className="text-green-600 dark:text-green-400" />
              </div>
              <span className="text-xs font-bold text-success flex items-center gap-1">
                <TrendingUp size={12} />
                +5%
              </span>
            </div>
            <h3 className="text-4xl font-bold text-text-primary mb-2">{stats.activeListings}</h3>
            <p className="text-sm text-text-secondary">Active Listings</p>
          </div>

          <div className="bg-white dark:bg-gray-800 rounded-[32px] p-8 border-2 border-gray-100 dark:border-gray-700 hover:shadow-xl transition-all">
            <div className="flex items-center justify-between mb-4">
              <div className="w-14 h-14 rounded-2xl bg-purple-50 dark:bg-purple-900/20 flex items-center justify-center">
                <DollarSign size={28} className="text-purple-600 dark:text-purple-400" />
              </div>
              <span className="text-xs font-bold text-success flex items-center gap-1">
                <TrendingUp size={12} />
                +18%
              </span>
            </div>
            <h3 className="text-4xl font-bold text-text-primary mb-2">{stats.totalRevenue}</h3>
            <p className="text-sm text-text-secondary">Platform Revenue</p>
          </div>
        </div>

        {/* User Management Section */}
        <div className="bg-white dark:bg-gray-800 rounded-[32px] border-2 border-gray-100 dark:border-gray-700 overflow-hidden">

          {/* Tabs and Search */}
          <div className="p-6 border-b border-gray-200 dark:border-gray-700">
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 mb-6">
              <h2 className="text-2xl font-bold text-text-primary">User Management</h2>

              <div className="relative">
                <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-text-secondary" />
                <input
                  type="text"
                  placeholder="Search users..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-12 pr-4 py-3 bg-gray-50 dark:bg-gray-700 border-2 border-gray-200 dark:border-gray-600 rounded-2xl text-sm text-text-primary focus:outline-none focus:border-primary focus:ring-4 focus:ring-primary/10 transition-all w-full lg:w-80"
                />
              </div>
            </div>

            {/* Tabs */}
            <div className="flex gap-2 overflow-x-auto pb-2">
              {[
                { id: 'pending', label: 'Pending', count: users.filter(u => u.approvalStatus === 'pending').length, color: 'amber' },
                { id: 'approved', label: 'Approved', count: users.filter(u => u.approvalStatus === 'approved').length, color: 'green' },
                { id: 'rejected', label: 'Rejected', count: users.filter(u => u.approvalStatus === 'rejected').length, color: 'red' },
                { id: 'all', label: 'All Users', count: users.length, color: 'gray' }
              ].map(tab => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`px-6 py-3 rounded-2xl font-semibold text-sm transition-all whitespace-nowrap ${activeTab === tab.id
                      ? 'bg-gradient-to-r from-primary to-green-600 text-white shadow-lg'
                      : 'bg-gray-100 dark:bg-gray-700 text-text-secondary hover:bg-gray-200 dark:hover:bg-gray-600'
                    }`}
                >
                  {tab.label}
                  <span className={`ml-2 px-2 py-0.5 rounded-full text-xs font-bold ${activeTab === tab.id
                      ? 'bg-white/30'
                      : 'bg-gray-200 dark:bg-gray-600'
                    }`}>
                    {tab.count}
                  </span>
                </button>
              ))}
            </div>
          </div>

          {/* Users Table */}
          <div className="overflow-x-auto">
            {filteredUsers.length === 0 ? (
              <div className="p-20 text-center">
                <Users size={64} className="mx-auto text-text-tertiary mb-4 opacity-30" />
                <h3 className="text-xl font-bold text-text-primary mb-2">No users found</h3>
                <p className="text-text-secondary">
                  {searchQuery ? 'Try adjusting your search query' : 'No users match the selected filter'}
                </p>
              </div>
            ) : (
              <table className="w-full">
                <thead>
                  <tr className="border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-700/50">
                    <th className="text-left text-xs font-bold text-text-secondary px-6 py-4 uppercase tracking-wider">User</th>
                    <th className="text-left text-xs font-bold text-text-secondary px-6 py-4 uppercase tracking-wider">Role</th>
                    <th className="text-left text-xs font-bold text-text-secondary px-6 py-4 uppercase tracking-wider">Status</th>
                    <th className="text-left text-xs font-bold text-text-secondary px-6 py-4 uppercase tracking-wider">Joined</th>
                    <th className="text-right text-xs font-bold text-text-secondary px-6 py-4 uppercase tracking-wider">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                  {filteredUsers.map(user => (
                    <tr key={user.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors group">
                      <td className="px-6 py-5">
                        <div className="flex items-center gap-4">
                          <img
                            src={`https://ui-avatars.com/api/?name=${encodeURIComponent(user.name || user.email || 'U')}&background=16a34a&color=fff&rounded=true&size=48`}
                            alt={user.name}
                            className="w-12 h-12 rounded-xl ring-2 ring-gray-200 dark:ring-gray-700"
                          />
                          <div>
                            <p className="font-bold text-text-primary">{user.name || 'Unknown'}</p>
                            <p className="text-sm text-text-secondary">{user.email}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-5">
                        <span className={`px-3 py-1.5 rounded-xl text-xs font-bold capitalize ${ROLE_COLORS[user.role] || 'bg-gray-100 text-gray-700'}`}>
                          {user.role?.replace('_', ' ') || 'user'}
                        </span>
                      </td>
                      <td className="px-6 py-5">
                        <span className={`px-3 py-1.5 rounded-xl text-xs font-bold capitalize flex items-center gap-1 w-fit ${STATUS_COLORS[user.approvalStatus] || 'bg-gray-100 text-gray-700'}`}>
                          {user.approvalStatus === 'pending' && <Clock size={12} />}
                          {user.approvalStatus === 'approved' && <CheckCircle2 size={12} />}
                          {user.approvalStatus === 'rejected' && <XCircle size={12} />}
                          {user.approvalStatus || 'pending'}
                        </span>
                      </td>
                      <td className="px-6 py-5 text-sm text-text-secondary">
                        {user.createdAt ? new Date(user.createdAt).toLocaleDateString() : 'N/A'}
                      </td>
                      <td className="px-6 py-5">
                        <div className="flex items-center justify-end gap-2">
                          {user.approvalStatus === 'pending' && (
                            <>
                              <button
                                onClick={() => handleApproveUser(user.id)}
                                disabled={actionLoading === user.id + '-approve'}
                                className="px-4 py-2 rounded-xl bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-300 hover:bg-green-100 dark:hover:bg-green-900/30 font-semibold text-sm transition-all flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                              >
                                {actionLoading === user.id + '-approve' ? (
                                  <><Loader2 size={16} className="animate-spin" /> Approving...</>
                                ) : (
                                  <><UserCheck size={16} /> Approve</>
                                )}
                              </button>
                              <button
                                onClick={() => handleRejectUser(user.id)}
                                disabled={actionLoading === user.id + '-reject'}
                                className="px-4 py-2 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-300 hover:bg-red-100 dark:hover:bg-red-900/30 font-semibold text-sm transition-all flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                              >
                                {actionLoading === user.id + '-reject' ? (
                                  <><Loader2 size={16} className="animate-spin" /> Rejecting...</>
                                ) : (
                                  <><UserX size={16} /> Reject</>
                                )}
                              </button>
                            </>
                          )}
                          {user.approvalStatus === 'approved' && (
                            <span className="text-sm text-text-secondary">Approved</span>
                          )}
                          {user.approvalStatus === 'rejected' && (
                            <button
                              onClick={() => handleApproveUser(user.id)}
                              className="px-4 py-2 rounded-xl bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 hover:bg-blue-100 dark:hover:bg-blue-900/30 font-semibold text-sm transition-all"
                            >
                              Re-approve
                            </button>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>

      </div>
    </div>
  );
};

export default Admin;

import React, { useState, useEffect } from 'react';
import {
    Heart, DollarSign, Clock, FileText, Check, AlertCircle,
    ChevronRight, Home, TrendingUp, Filter, ArrowUpRight
} from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import PageHeader from '../components/PageHeader';



import { collection, query, where, getDocs } from 'firebase/firestore';
import { db } from '../services/firebase';
import { getProjectsForUser } from '../services/dashboardData';



export default function AffordableHousing() {
    const { userData } = useAuth();
    const [tab, setTab] = useState('projects');
    const [projects, setProjects] = useState([]);
    const [programs, setPrograms] = useState([]);
    const [loading, setLoading] = useState(true);

    const toSafeNumber = (value, fallback = 0) => {
        const parsed = Number(value);
        return Number.isFinite(parsed) ? parsed : fallback;
    };

    useEffect(() => {
        const fetchPrograms = async () => {
            try {
                const snap = await getDocs(collection(db, 'fundingPrograms'));
                setPrograms(snap.docs.map(d => ({ id: d.id, ...d.data() })));
            } catch (err) {
                console.error("Error fetching programs:", err);
                setPrograms([]);
            }
        };
        fetchPrograms();
    }, []);

    useEffect(() => {
        const fetchAffordableProjects = async () => {
            if (!userData?.uid) {
                setProjects([]);
                setLoading(false);
                return;
            }
            try {
                const scopedProjects = await getProjectsForUser(userData);
                const projectData = scopedProjects
                    .map(data => ({
                        id: data.id,
                        name: data.name || 'Unnamed Project',
                        city: data.city || data.propertyCity || 'Unknown Location',
                        amiLevel: data.amiLevel || data.targetAMI || '60% AMI',
                        units: toSafeNumber(data.totalUnits ?? data.units),
                        affordableUnits: toSafeNumber(data.affordableUnits),
                        term: data.term || (data.affordabilityTerm ? `${data.affordabilityTerm} years` : '30 years'),
                        fundingStatus: data.fundingStatus || (toSafeNumber(data.fundingAmount) > 0 ? 'awarded' : 'applying'),
                        fundingAmount: toSafeNumber(data.fundingAmount),
                        program: data.fundingProgram || 'Undecided',
                        compliancePeriod: data.compliancePeriod || (data.affordabilityTerm ? `${data.affordabilityTerm} years` : '15 years'),
                        isAffordable: Boolean(data.isAffordable || data.affordableHousingOptIn || toSafeNumber(data.affordableUnits) > 0),
                        complianceRequirements: Array.isArray(data.complianceRequirements) ? data.complianceRequirements : [],
                    }))
                    .filter(project => project.isAffordable || project.affordableUnits > 0);

                setProjects(projectData);
            } catch (error) {
                console.error("Error fetching affordable projects:", error);
                setProjects([]);
            } finally {
                setLoading(false);
            }
        };

        fetchAffordableProjects();
    }, [userData]);

    const activeProjectsCount = projects.length;
    const totalAffordableUnits = projects.reduce((sum, project) => sum + toSafeNumber(project.affordableUnits), 0);
    const fundingSecuredAmount = projects.reduce((sum, project) => sum + toSafeNumber(project.fundingAmount), 0);
    const complianceActiveCount = projects.filter(project => project.fundingStatus === 'awarded').length;

    const defaultComplianceItems = [
        { label: 'Annual Income Verification', due: 'TBD', status: 'upcoming' },
        { label: 'Unit Inspection Report', due: 'TBD', status: 'upcoming' },
        { label: 'Program Compliance Report', due: 'TBD', status: 'upcoming' },
    ];

    return (
        <div className="h-full overflow-y-auto">
            <div className="max-w-5xl mx-auto p-6 lg:p-8">
                <PageHeader
                    title="Affordable Housing"
                    subtitle="Track affordable housing projects, AMI commitments and public funding programs."
                />

                {loading && (
                    <div className="mb-6 p-4 rounded-xl border border-border-light bg-surface text-sm text-text-secondary">
                        Loading affordable housing data...
                    </div>
                )}

                {/* Stats Row */}
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
                    {[
                        ['Active Projects', String(activeProjectsCount), Heart, 'success'],
                        ['Affordable Units', String(totalAffordableUnits), Home, 'primary'],
                        ['Funding Secured', `$${fundingSecuredAmount.toLocaleString()}`, DollarSign, 'info'],
                        ['Compliance Active', String(complianceActiveCount), Check, 'warning'],
                    ].map(([label, value, Icon, color]) => (
                        <div key={label} className={`bg-${color}/5 border border-${color}/10 rounded-xl p-4`}>
                            <Icon size={18} className={`text-${color} mb-2`} />
                            <p className="text-xs text-text-tertiary font-bold uppercase">{label}</p>
                            <p className="text-xl font-bold text-text-primary">{value}</p>
                        </div>
                    ))}
                </div>

                {/* Tabs */}
                <div className="flex gap-1 border-b border-border-light mb-6">
                    {[['projects', 'My Projects'], ['programs', 'Funding Programs'], ['compliance', 'Compliance']].map(([key, label]) => (
                        <button key={key} onClick={() => setTab(key)}
                            className={`px-5 py-2.5 text-sm font-bold border-b-2 transition-all ${tab === key ? 'border-primary text-primary' : 'border-transparent text-text-secondary hover:text-text-primary'
                                }`}>
                            {label}
                        </button>
                    ))}
                </div>

                {/* Projects Tab */}
                {tab === 'projects' && (
                    <div className="space-y-4">
                        {projects.length === 0 ? (
                            <div className="bg-surface border border-border-light rounded-2xl p-8 text-center text-text-secondary">
                                No affordable housing projects found yet.
                            </div>
                        ) : projects.map(proj => (
                            <div key={proj.id} className="bg-surface border border-border-light rounded-2xl p-5 shadow-sm hover:shadow-md transition-all">
                                <div className="flex items-start justify-between mb-3">
                                    <div>
                                        <h3 className="text-sm font-bold text-text-primary">{proj.name}</h3>
                                        <p className="text-xs text-text-secondary">{proj.city} · {proj.units} units ({proj.affordableUnits} affordable)</p>
                                    </div>
                                    <span className={`px-2.5 py-0.5 rounded-full text-xs font-bold ${proj.fundingStatus === 'awarded' ? 'bg-success/10 text-success' :
                                        proj.fundingStatus === 'applying' ? 'bg-warning/10 text-warning' :
                                            'bg-surface-element text-text-tertiary'
                                        }`}>{proj.fundingStatus}</span>
                                </div>
                                <div className="grid grid-cols-4 gap-3">
                                    {[
                                        ['AMI Level', proj.amiLevel],
                                        ['Term', proj.term],
                                        ['Program', proj.program],
                                        ['Funding', proj.fundingAmount ? `$${proj.fundingAmount.toLocaleString()}` : 'Pending'],
                                    ].map(([k, v]) => (
                                        <div key={k} className="bg-surface-element/50 rounded-lg p-2.5">
                                            <p className="text-[9px] font-bold text-text-tertiary uppercase">{k}</p>
                                            <p className="text-xs font-semibold text-text-primary mt-0.5">{v}</p>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {/* Programs Tab */}
                {tab === 'programs' && (
                    <div className="space-y-4">
                        {programs.length === 0 ? (
                            <div className="bg-surface border border-border-light rounded-2xl p-8 text-center text-text-secondary">
                                No funding programs available right now.
                            </div>
                        ) : programs.map(prog => (
                            <div key={prog.id} className="bg-surface border border-border-light rounded-2xl p-5 shadow-sm">
                                <div className="flex items-start justify-between mb-2">
                                    <div>
                                        <h3 className="text-sm font-bold text-text-primary">{prog.name}</h3>
                                        <p className="text-xs text-text-secondary mt-0.5">{prog.desc}</p>
                                    </div>
                                    <span className={`px-2.5 py-0.5 rounded-full text-xs font-bold shrink-0 ${prog.status === 'closing_soon' ? 'bg-danger/10 text-danger' :
                                        'bg-success/10 text-success'
                                        }`}>{prog.status === 'closing_soon' ? 'Closing Soon' : 'Open'}</span>
                                </div>
                                <div className="flex items-center gap-4 mt-3 text-xs text-text-secondary">
                                    <span className="flex items-center gap-1"><FileText size={12} /> {prog.type}</span>
                                    <span className="flex items-center gap-1"><Clock size={12} /> Deadline: {prog.deadline}</span>
                                    <span className="flex items-center gap-1"><DollarSign size={12} /> Max: {prog.maxAward}</span>
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {/* Compliance Tab */}
                {tab === 'compliance' && (
                    <div className="space-y-4">
                        <div className="bg-info/5 border border-info/10 rounded-xl p-4 text-xs text-text-secondary mb-2">
                            Track compliance periods, reporting requirements and upcoming deadlines for all affordable housing commitments.
                        </div>
                        {projects.filter(p => p.fundingStatus === 'awarded').length === 0 ? (
                            <div className="bg-surface border border-border-light rounded-2xl p-8 text-center text-text-secondary">
                                No awarded projects with active compliance requirements yet.
                            </div>
                        ) : projects.filter(p => p.fundingStatus === 'awarded').map(proj => (
                            <div key={proj.id} className="bg-surface border border-border-light rounded-2xl p-5 shadow-sm">
                                <h3 className="text-sm font-bold text-text-primary mb-3">{proj.name} — Compliance Tracker</h3>
                                <div className="grid grid-cols-3 gap-3 mb-4">
                                    {[
                                        ['Compliance Period', proj.compliancePeriod],
                                        ['AMI Commitment', proj.amiLevel],
                                        ['Affordable Units', String(proj.affordableUnits)],
                                    ].map(([k, v]) => (
                                        <div key={k} className="bg-surface-element rounded-lg p-3 text-center">
                                            <p className="text-[9px] font-bold text-text-tertiary uppercase">{k}</p>
                                            <p className="text-sm font-bold text-text-primary mt-0.5">{v}</p>
                                        </div>
                                    ))}
                                </div>
                                <div className="space-y-2">
                                    {(proj.complianceRequirements.length > 0 ? proj.complianceRequirements : defaultComplianceItems).map((r, i) => (
                                        <div key={i} className="flex items-center justify-between p-3 rounded-lg border border-border-light">
                                            <span className="text-xs font-medium text-text-primary">{r.label}</span>
                                            <div className="flex items-center gap-2">
                                                <span className="text-[10px] text-text-tertiary">Due: {r.due || 'TBD'}</span>
                                                <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${r.status === 'complete' ? 'bg-success/10 text-success' : 'bg-info/10 text-info'}`}>
                                                    {r.status || 'upcoming'}
                                                </span>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Scale, Star, MapPin, Search, Filter, Check, ChevronRight, Shield, Phone, Mail, Briefcase } from 'lucide-react';
import { listAttorneys } from '../services/firestoreService';
import { useAuth } from '../contexts/AuthContext';
import PageHeader from '../components/PageHeader';

export default function AttorneyMarketplace() {
    const { userData } = useAuth();
    const [attorneys, setAttorneys] = useState([]);
    const [search, setSearch] = useState('');
    const [stateFilter, setStateFilter] = useState('');
    const [selectedAttorney, setSelectedAttorney] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchAttorneys = async () => {
            try {
                const data = await listAttorneys();
                // Map Firestore structure or use default fallback structure
                const mappedData = data.map(att => ({
                    id: att.id,
                    name: att.name || 'Unknown Attorney',
                    firm: att.firm || 'Independent Practice',
                    barNumber: att.barNumber || 'N/A',
                    barState: att.barState || 'Unknown',
                    specialties: att.specialties || [],
                    rating: att.rating || 0.0,
                    completedDeals: att.completedDeals || 0,
                    location: att.location || 'Unknown Location',
                    verified: att.verified || false,
                    hourlyRate: att.hourlyRate || 0
                }));
                setAttorneys(mappedData);
            } catch (error) {
                console.error('Error fetching attorneys:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchAttorneys();
    }, []);

    const filtered = attorneys.filter(a => {
        if (search && !a.name.toLowerCase().includes(search.toLowerCase()) && !a.firm.toLowerCase().includes(search.toLowerCase())) return false;
        if (stateFilter && a.barState !== stateFilter) return false;
        return true;
    });

    const states = [...new Set(attorneys.map(a => a.barState))];

