    const [loading, setLoading] = useState(true);
    const navigate = useNavigate();
    const container = useRef();
    const [lotSizeMinFilter, setLotSizeMinFilter] = useState('2500');
    const [lotSizeMaxFilter, setLotSizeMaxFilter] = useState('15000');
    const [overlayFilters, setOverlayFilters] = useState({
        tod: false,
        historic: false,
        opportunity: false,
        commercial: false,
    });
    const [minCapRateFilter, setMinCapRateFilter] = useState(5.5);
    const [targetIrrFilter, setTargetIrrFilter] = useState(18);

    const resetAllFilters = () => {
        setLotSizeMinFilter('2500');
        setLotSizeMaxFilter('15000');
        setOverlayFilters({
            tod: false,
            historic: false,
            opportunity: false,
            commercial: false,
        });
        setMinCapRateFilter(5.5);
        setTargetIrrFilter(18);
    };

    const toggleOverlayFilter = (filterKey) => {
        setOverlayFilters(previous => ({
            ...previous,
            [filterKey]: !previous[filterKey],
        }));
    };

    const getPropertyLotSize = (property) => {
        const directLotSize = Number(property.lotSize);
        if (Number.isFinite(directLotSize) && directLotSize > 0) return directLotSize;

        const minLotSize = Number(property.lotSizeMin);
        const maxLotSize = Number(property.lotSizeMax);
        if (Number.isFinite(minLotSize) && Number.isFinite(maxLotSize) && minLotSize > 0 && maxLotSize > 0) {
            return Math.round((minLotSize + maxLotSize) / 2);
        }

        const lotSizeRange = String(property.lotSizeRange || '');
        const numericValues = lotSizeRange.match(/\d[\d,]*/g)?.map(value => Number(value.replace(/,/g, ''))) || [];
        if (numericValues.length === 1) return numericValues[0];
        if (numericValues.length >= 2) return Math.round((numericValues[0] + numericValues[1]) / 2);

        return 0;
    };

    const parsePercentValue = (value) => {
        if (value === null || value === undefined) return NaN;
        if (typeof value === 'number') return Number.isFinite(value) ? value : NaN;
        const normalized = String(value).replace('%', '').trim();
        const parsed = Number(normalized);
        return Number.isFinite(parsed) ? parsed : NaN;
    };

    const getPropertyCapRate = (property) => {
        const candidates = [property.capRate, property.minCapRate, property.cap_rate];
        for (const candidate of candidates) {
            const parsed = parsePercentValue(candidate);
            if (Number.isFinite(parsed)) return parsed;
        }
        return NaN;
    };

    const getPropertyTargetIrr = (property) => {
        const candidates = [property.targetIRR, property.targetIrr, property.irr, property.expectedReturn];
        for (const candidate of candidates) {
            const parsed = parsePercentValue(candidate);
            if (Number.isFinite(parsed)) return parsed;
        }
        return NaN;
    };

    const filteredProperties = useMemo(() => {
        const minLotInput = Number(lotSizeMinFilter);
        const maxLotInput = Number(lotSizeMaxFilter);
        const minLotFilter = Number.isFinite(minLotInput) ? minLotInput : 0;
        const maxLotFilter = Number.isFinite(maxLotInput) ? maxLotInput : Number.MAX_SAFE_INTEGER;
        const normalizedMinLot = Math.min(minLotFilter, maxLotFilter);
        const normalizedMaxLot = Math.max(minLotFilter, maxLotFilter);
        const enabledOverlayKeys = Object.entries(overlayFilters)
            .filter(([, isEnabled]) => isEnabled)
            .map(([key]) => key);

        return properties.filter(property => {
            const propertyLotSize = getPropertyLotSize(property);
            if (propertyLotSize > 0 && (propertyLotSize < normalizedMinLot || propertyLotSize > normalizedMaxLot)) {
                return false;
            }

            const propertyCapRate = getPropertyCapRate(property);
            if (Number.isFinite(propertyCapRate) && propertyCapRate < minCapRateFilter) {
                return false;
            }

            const propertyIrr = getPropertyTargetIrr(property);
            if (Number.isFinite(propertyIrr) && propertyIrr < targetIrrFilter) {
                return false;
            }

            const overlayText = [
                ...(Array.isArray(property.overlayFlags) ? property.overlayFlags : []),
                ...(Array.isArray(property.tags) ? property.tags : []),
                property.zoningDistrict,
                property.buildPotential,
            ].join(' ').toLowerCase();

            if (enabledOverlayKeys.length === 0) {
                return true;
            }

            const overlayMatches = {
                tod: overlayText.includes('tod') || overlayText.includes('transit'),
                historic: overlayText.includes('historic'),
                opportunity: overlayText.includes('opportunity'),
                commercial: overlayText.includes('commercial') || overlayText.includes('c1') || overlayText.includes('c2'),
            };

            return enabledOverlayKeys.some(key => overlayMatches[key]);
        });
    }, [properties, lotSizeMinFilter, lotSizeMaxFilter, overlayFilters, minCapRateFilter, targetIrrFilter]);

    useEffect(() => {
        const fetchProperties = async () => {
            try {
                const listingsSnap = await getDocs(collection(db, 'listings'));
                const parcelsSnap = await getDocs(collection(db, 'parcels'));
                
                const parcelsMap = {};
                parcelsSnap.docs.forEach(doc => {
                    parcelsMap[doc.id] = { id: doc.id, ...doc.data() };
                });

                const propsData = listingsSnap.docs
                    .map(doc => {
                        const listingData = { id: doc.id, ...doc.data() };
                        const parcelData = parcelsMap[listingData.parcelId] || {};
                        const propertyData = { ...parcelData, ...listingData, id: listingData.id, parcelId: parcelData.id };
                        
                        const lotSize = getPropertyLotSize(propertyData);
                        const normalizedTags = Array.isArray(propertyData.tags) && propertyData.tags.length > 0
                            ? propertyData.tags
                            : (Array.isArray(propertyData.overlayFlags) ? propertyData.overlayFlags.slice(0, 2) : []);

                        return {
                            ...propertyData,
                            title: propertyData.title || `${propertyData.city || 'Unknown City'} Opportunity`,
                            zoning: propertyData.zoning || propertyData.zoningDistrict || 'TBD',
                            lotSize,
                            lotSizeLabel: lotSize > 0 ? lotSize.toLocaleString() : (propertyData.lotSizeRange || 'TBD'),
                            tags: normalizedTags,
                            imageGradient: propertyData.imageGradient || 'from-emerald-200 via-emerald-100 to-emerald-50',
                            matchScore: getMatchScore(propertyData),
                        };
                    })
                    .sort((firstProperty, secondProperty) => secondProperty.matchScore - firstProperty.matchScore);
                setProperties(propsData);
            } catch (error) {
                console.error('Error fetching properties:', error);
                setProperties([]);
            } finally {
                setLoading(false);
            }
        };

        fetchProperties();
    }, []);

    useGSAP(() => {
        if (properties.length > 0) {
            gsap.from('.opportunity-card', {
                y: 50,
                opacity: 0,
                duration: 0.6,
                stagger: 0.1,
                ease: 'power3.out',
                clearProps: 'all'
            });
        }
    }, { dependencies: [properties], scope: container });

    return (
        <div className="flex h-[calc(100vh-73px)] overflow-hidden bg-background" ref={container}>

            {/* Left Sidebar Filters */}
            <div className="w-[280px] shrink-0 bg-surface border-r border-light flex flex-col h-full overflow-y-auto z-10">
                <div className="p-4 border-b border-light flex justify-between items-center sticky top-0 bg-surface z-10">
                    <h2 className="font-bold">Filters</h2>
                    <button className="text-sm text-primary hover:underline" onClick={resetAllFilters}>Reset All</button>
                </div>

                <div className="p-5 flex flex-col gap-6">

                    {/* Property Specs */}
                    <div>
                        <p className="text-xs font-bold text-text-secondary uppercase tracking-widest mb-4">PROPERTY SPECS</p>
                        <label className="text-sm font-medium mb-2 block">Lot Size (sq ft)</label>
                        <div className="flex items-center gap-2">
                            <input type="number" placeholder="2500" value={lotSizeMinFilter} onChange={(event) => setLotSizeMinFilter(event.target.value)} className="w-full border border-light rounded p-2 text-sm focus:outline-primary bg-surface-hover" />
                            <span className="text-text-secondary">-</span>
                            <input type="number" placeholder="15000" value={lotSizeMaxFilter} onChange={(event) => setLotSizeMaxFilter(event.target.value)} className="w-full border border-light rounded p-2 text-sm focus:outline-primary bg-surface-hover" />
                        </div>
                    </div>

                    {/* Zoning & Overlays */}
                    <div className="border-t border-light pt-6">
                        <div className="flex justify-between items-center mb-4 cursor-pointer">
                            <p className="font-bold text-sm">Zoning & Overlays</p>
                            <ChevronDown size={16} className="text-text-secondary" />
                        </div>
                        <div className="flex flex-col gap-3">
                            <button type="button" onClick={() => toggleOverlayFilter('tod')} className="flex items-center gap-2 text-sm cursor-pointer group text-left">
                                <div className={`w-4 h-4 rounded border flex items-center justify-center ${overlayFilters.tod ? 'border-primary bg-primary text-white' : 'border-border-medium bg-surface text-transparent group-hover:border-primary'}`}>
                                    <Check size={12} strokeWidth={3} />
                                </div>
                                <span className={overlayFilters.tod ? 'group-hover:text-primary transition-colors' : 'text-text-secondary group-hover:text-text-primary transition-colors'}>Transit Oriented (TOD)</span>
                            </button>
                            <button type="button" onClick={() => toggleOverlayFilter('historic')} className="flex items-center gap-2 text-sm cursor-pointer group text-left">
                                <div className={`w-4 h-4 rounded border flex items-center justify-center ${overlayFilters.historic ? 'border-primary bg-primary text-white' : 'border-border-medium bg-surface text-transparent group-hover:border-primary'}`}>
                                    <Check size={12} strokeWidth={3} />
                                </div>
                                <span className={overlayFilters.historic ? 'group-hover:text-primary transition-colors' : 'text-text-secondary group-hover:text-text-primary transition-colors'}>Historic District</span>
                            </button>
                            <button type="button" onClick={() => toggleOverlayFilter('opportunity')} className="flex items-center gap-2 text-sm cursor-pointer group text-left">
                                <div className={`w-4 h-4 rounded border flex items-center justify-center ${overlayFilters.opportunity ? 'border-primary bg-primary text-white' : 'border-border-medium bg-surface text-transparent group-hover:border-primary'}`}>
                                    <Check size={12} strokeWidth={3} />
                                </div>
                                <span className={overlayFilters.opportunity ? 'group-hover:text-primary transition-colors' : 'text-text-secondary group-hover:text-text-primary transition-colors'}>Opportunity Zone</span>
                            </button>
                            <button type="button" onClick={() => toggleOverlayFilter('commercial')} className="flex items-center gap-2 text-sm cursor-pointer group text-left">
                                <div className={`w-4 h-4 rounded border flex items-center justify-center ${overlayFilters.commercial ? 'border-primary bg-primary text-white' : 'border-border-medium bg-surface text-transparent group-hover:border-primary'}`}>
                                    <Check size={12} strokeWidth={3} />
                                </div>
                                <span className={overlayFilters.commercial ? 'group-hover:text-primary transition-colors' : 'text-text-secondary group-hover:text-text-primary transition-colors'}>Commercial Overlay (C1/C2)</span>
                            </button>
                        </div>
                    </div>

                    {/* Financial Targets */}
                    <div className="border-t border-light pt-6">
                        <div className="flex justify-between items-center mb-4 cursor-pointer">
                            <p className="font-bold text-sm">Financial Targets</p>
                            <ChevronDown size={16} className="text-text-secondary" />
                        </div>

                        <div className="mb-6">
                            <div className="flex justify-between text-sm mb-2 text-text-secondary">
                                <span>Min Cap Rate</span>
                                <span className="font-bold text-text-primary">{minCapRateFilter.toFixed(1)}%</span>
                            </div>
                            <input
                                type="range"
                                min="2"
                                max="12"
                                step="0.1"
                                value={minCapRateFilter}
                                onChange={(event) => setMinCapRateFilter(Number(event.target.value))}
                                className="w-full mt-3 accent-primary"
                            />
                        </div>

                        <div>
                            <div className="flex justify-between text-sm mb-2 text-text-secondary">
                                <span>Target IRR</span>
                                <span className="font-bold text-text-primary">{targetIrrFilter.toFixed(1)}%</span>
                            </div>
                            <input
                                type="range"
                                min="8"
                                max="35"
                                step="0.5"
                                value={targetIrrFilter}
                                onChange={(event) => setTargetIrrFilter(Number(event.target.value))}
                                className="w-full mt-3 accent-primary"
                            />
                        </div>
                    </div>

                    {/* AI Analyst Block */}
                    <div className="card p-4 bg-info-bg border-info border-opacity-20 flex flex-col gap-3 mt-4 shadow-sm relative overflow-hidden">
                        <div className="absolute -right-4 -top-4 text-info opacity-10 rotate-12">
                            <Zap size={64} fill="currentColor" />
                        </div>
                        <div className="flex items-center gap-2 font-bold text-info">
                            <Zap size={16} className="fill-current" /> AI Analyst
                        </div>
                        <p className="text-sm text-info text-opacity-80">Get custom alerts for off-market deals matching your criteria.</p>
                        <button className="text-info font-bold text-sm text-left hover:underline">Configure Alerts →</button>
                    </div>

                </div>
            </div>

            {/* Main Content Area */}
            <div className="flex-1 flex flex-col min-w-0 bg-background">

                {/* Top Bar inside content */}
                <div className="p-6 pb-2 flex justify-between items-end sticky top-0 bg-background z-10 backdrop-blur-sm shadow-sm">
                    <div>
                        <h1 className="text-h2 font-bold mb-1">Marketplace Opportunities</h1>
                        <p className="text-text-secondary">
                            {loading
                                ? 'Loading anonymized listings...'
                                : `Showing ${filteredProperties.length} anonymized site${filteredProperties.length === 1 ? '' : 's'} matching your criteria`}
                        </p>
                    </div>

                    <div className="flex items-center gap-3">
                        <button className="btn btn-secondary flex items-center gap-2 bg-white text-text-secondary font-bold text-sm py-2 px-4 shadow-sm border border-border-light hover:border-border-medium hover:text-text-primary">
                            <Settings size={16} /> Saved Searches
                        </button>
                        <div className="flex bg-white rounded-md shadow-sm border border-light p-1">
                            <button className="p-1 px-2.5 rounded bg-surface-hover shadow-sm"><div className="w-4 h-4 grid grid-cols-2 gap-[2px]"><div className="bg-primary rounded-[1px]"></div><div className="bg-primary rounded-[1px]"></div><div className="bg-primary rounded-[1px]"></div><div className="bg-primary rounded-[1px]"></div></div></button>
                            <button className="p-1 px-2.5 rounded text-light hover:text-text-secondary"><div className="w-4 h-4 flex flex-col gap-[2px]"><div className="h-1 w-full bg-current rounded-[1px]"></div><div className="h-1 w-full bg-current rounded-[1px]"></div><div className="h-1 w-full bg-current rounded-[1px]"></div></div></button>
                        </div>
                        <button className="btn btn-primary flex items-center gap-2 shadow-sm font-bold ml-2">
                            Sort: Match Score <ChevronDown size={14} />
                        </button>
                    </div>
                </div>

                {/* Opportunity Cards Grid */}
                <div className="p-6 overflow-y-auto flex-1 h-full">
                    {loading ? (
                        <div className="flex items-center justify-center p-12 text-text-secondary">
                            <Loader2 className="animate-spin mr-2" /> Loading Market Data...
                        </div>
                    ) : filteredProperties.length === 0 ? (
                        <div className="flex items-center justify-center p-12 text-text-secondary">
                            No properties match your current filters.
                        </div>
                    ) : (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-12">

                            {filteredProperties.map((prop) => (
                                <div key={prop.id} className="card opportunity-card bg-white flex flex-col border border-border-light shadow-sm hover:shadow-lg transition-all hover:-translate-y-1 opacity-0">

                                    {/* Image/Map Placeholder area */}
                                    <div className={`h-[200px] relative overflow-hidden ${prop.imageGradient?.includes('bg-') ? prop.imageGradient : `bg-gradient-to-br ${prop.imageGradient}`}`}>
                                        {/* Special condition for map SVG simulation if present in data */}
                                        {prop.imageGradient?.includes('bg-') && (
                                            <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="none">
                                                <rect width="100%" height="100%" fill="#a7f3d0" />
                                                <path d="M 0 50 Q 80 80 150 40 T 300 20 T 400 90 L 400 200 L 0 200 Z" fill="#bae6fd" opacity="0.8" />
                                                <circle cx="200" cy="120" r="4" fill="#ef4444" />
                                                <circle cx="200" cy="120" r="20" fill="#ef4444" opacity="0.3" />
                                            </svg>
                                        )}

                                        {/* Blurred map simulation for gradients */}
                                        {!prop.imageGradient?.includes('bg-') && (
                                            <div className="absolute inset-0 bg-map-pattern opacity-30 blur-[2px] scale-110"></div>
                                        )}

                                        <div className="absolute inset-0 bg-gradient-to-t from-[rgba(15,23,42,0.8)] to-transparent"></div>

                                        {/* Overlay items */}
                                        <div className="absolute top-3 left-3 flex gap-2">
                                            {prop.tags?.map((tag, idx) => (
                                                <span key={idx} className={`${idx === 0 ? 'bg-white text-info' : 'bg-[#1e293b] text-white'} text-[10px] font-bold px-2 py-1 rounded shadow-sm`}>
                                                    {tag}
                                                </span>
                                            ))}
                                        </div>
                                        <button className="absolute top-3 right-3 w-8 h-8 rounded-full bg-white bg-opacity-20 backdrop-blur-md flex items-center justify-center text-white hover:bg-white hover:text-danger transition-colors border border-white border-opacity-30">
                                            <Heart size={16} />
                                        </button>

                                        <div className="absolute inset-0 flex items-center justify-center text-white text-opacity-60 text-lg font-mono tracking-widest pointer-events-none">
                                            300×300
                                        </div>

                                        <div className="absolute bottom-4 left-4 right-4 flex justify-between items-end">
                                            <div>
                                                <p className="text-[10px] text-white text-opacity-80 font-bold uppercase tracking-widest mb-1">ANCHORPLOT MATCH</p>
                                                <p className="text-3xl font-bold text-white leading-none">{prop.matchScore}%</p>
                                            </div>
                                            <div className="w-10 h-10 rounded-full bg-primary flex items-center justify-center text-white shadow-lg border-2 border-primary-hover">
                                                <BarChart2 size={20} />
                                            </div>
                                        </div>
                                    </div>

                                    {/* Card Content */}
                                    <div className="p-5 flex flex-col flex-1">
                                        <h3 className="font-bold text-lg mb-1 line-clamp-1">{prop.title}</h3>
                                        <p className="text-sm text-text-secondary mb-4 line-clamp-1">Neighborhood Band: {prop.neighborhoodBand}</p>

                                        <div className="flex gap-4 mb-5 pb-4 border-b border-light">
                                            <div className="flex-1">
                                                <p className="text-[10px] uppercase font-bold text-light tracking-widest mb-1">ZONING</p>
                                                <p className="font-bold text-sm">{prop.zoning}</p>
                                            </div>
                                            <div className="w-px bg-light"></div>
                                            <div className="flex-1">
                                                <p className="text-[10px] uppercase font-bold text-light tracking-widest mb-1">LOT SIZE</p>
                                                <p className="font-bold text-sm">{prop.lotSizeLabel}{prop.lotSize > 0 ? ' sq ft' : ''}</p>
                                            </div>
                                        </div>

                                        <div className="mb-6 flex-1">
                                            <p className="text-[10px] uppercase font-bold text-light tracking-widest mb-2">BUILD POTENTIAL</p>
                                            <div className="flex items-center gap-2 text-info font-bold text-sm">
                                                <div className="p-1.5 bg-info-bg rounded"><Map size={14} className="text-info" /></div>
                                                {prop.buildPotential}
                                            </div>
                                        </div>

                                        <div className="flex gap-3 justify-between items-center mt-auto">
                                            <button
                                                className="text-text-secondary font-bold text-sm hover:text-primary transition-colors"
                                                onClick={() => navigate(`/app/marketplace/${prop.id}`)}
                                            >
                                                View Details
                                            </button>
                                            <button
                                                className="btn btn-primary bg-primary text-white shadow-sm font-bold w-[120px]"
                                                onClick={() => navigate(`/app/marketplace/${prop.id}`)}
                                            >
                                                Submit Pitch
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            ))}

                        </div>
                    )}

                    {/* Pagination */}
                    <div className="flex justify-center items-center gap-2 mb-8">
                        <button className="w-8 h-8 rounded flex items-center justify-center bg-white border border-light text-text-secondary hover:border-primary hover:text-primary transition-colors"><ChevronDown size={14} className="rotate-90" /></button>
                        <button className="w-8 h-8 rounded flex items-center justify-center bg-primary border border-primary text-white font-bold text-sm shadow-sm">1</button>
                        <button className="w-8 h-8 rounded flex items-center justify-center bg-white border border-light text-text-primary hover:border-primary hover:text-primary transition-colors font-bold text-sm">2</button>
                        <button className="w-8 h-8 rounded flex items-center justify-center bg-white border border-light text-text-primary hover:border-primary hover:text-primary transition-colors font-bold text-sm">3</button>
                        <span className="text-text-secondary tracking-widest">...</span>
                        <button className="w-8 h-8 rounded flex items-center justify-center bg-white border border-light text-text-primary hover:border-primary hover:text-primary transition-colors font-bold text-sm">8</button>
                        <button className="w-8 h-8 rounded flex items-center justify-center bg-white border border-light text-text-secondary hover:border-primary hover:text-primary transition-colors"><ChevronDown size={14} className="-rotate-90" /></button>
                    </div>
                </div>

            </div>

        </div>
    );
};

export default Marketplace;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
    ArrowLeft, FileText, Milestone, PieChart, MessageSquare, Shield,
    Check, Clock, AlertCircle, DollarSign, Users, Building2, Briefcase,
    ChevronRight, Plus, Send, Download, Upload
} from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import { getProject, updateProject, addMilestone, sendMessage, subscribeToMessages, updateEquityLedger } from '../services/firestoreService';

const TABS = [
    { key: 'overview', label: 'Overview', icon: Building2 },
    { key: 'milestones', label: 'Milestones', icon: Milestone },
    { key: 'equity', label: 'Equity Ledger', icon: PieChart },
    { key: 'documents', label: 'Documents', icon: FileText },
    { key: 'messages', label: 'Messages', icon: MessageSquare },
    { key: 'compliance', label: 'Compliance', icon: Shield },
];

const MILESTONE_PHASES = [
    { key: 'planning', label: 'Planning', color: '#3b82f6' },
    { key: 'permitting', label: 'Permitting', color: '#f59e0b' },
    { key: 'funding_close', label: 'Funding Close', color: '#8b5cf6' },
    { key: 'construction', label: 'Construction', color: '#22c55e' },
    { key: 'completion', label: 'Completion', color: '#06b6d4' },
];

export default function ProjectWorkspace() {
    const { projectId } = useParams();
    const navigate = useNavigate();
    const { userData } = useAuth();
    const [project, setProject] = useState(null);
    const [tab, setTab] = useState('overview');
    const [loading, setLoading] = useState(true);
    const [messages, setMessages] = useState([]);
    const [newMessage, setNewMessage] = useState('');

    useEffect(() => {
        async function load() {
            try {
                const p = await getProject(projectId);
                setProject(p || {
                    id: projectId, name: 'Project', status: 'active', phase: 'planning',
                    milestones: [], equityLedger: [], totalBudget: 0, deployedBudget: 0,
                });
            } catch (e) { console.error(e); }
            setLoading(false);
        }
        load();
    }, [projectId]);

    useEffect(() => {
        if (!projectId) return;
        const unsub = subscribeToMessages(projectId, (msgs) => setMessages(msgs));
        return unsub;
    }, [projectId]);

    const handleSendMessage = async () => {
        if (!newMessage.trim()) return;
        await sendMessage({
            projectId,
            senderId: userData?.uid,
            senderName: userData?.name || 'User',
            text: newMessage,
        });
        setNewMessage('');
    };

    const formatCurrency = (n) => n ? `$${Number(n).toLocaleString()}` : '$0';

    if (loading) return (
        <div className="h-full flex items-center justify-center">
            <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin" />
        </div>
    );

    const normalizeMilestoneStatus = (status) => {
        const normalized = String(status || '').toLowerCase();
        if (['completed', 'complete', 'done'].includes(normalized)) return 'completed';
        if (['in-progress', 'in_progress', 'active', 'ongoing'].includes(normalized)) return 'in-progress';
        return 'pending';
    };

    const equityData = Array.isArray(project?.equityLedger) ? project.equityLedger : [];
    const milestones = Array.isArray(project?.milestones)
        ? project.milestones.map((milestone, index) => ({
            ...milestone,
            label: milestone.label || milestone.title || `Milestone ${index + 1}`,
            status: normalizeMilestoneStatus(milestone.status),
        }))
        : [];

    const projectDocuments = Array.isArray(project?.documents) ? project.documents : [];
    const complianceCheckpoints = Array.isArray(project?.complianceCheckpoints)
        ? project.complianceCheckpoints
        : [];

    return (
        <div className="h-full overflow-y-auto">
            <div className="max-w-5xl mx-auto p-6 lg:p-8">

                {/* Back */}
                <button onClick={() => navigate('/app/deal-room')}
                    className="flex items-center gap-2 text-sm text-text-secondary hover:text-primary font-medium mb-4 transition-colors">
                    <ArrowLeft size={16} /> Back to Deal Room
                </button>

                {/* Header */}
                <div className="flex items-center justify-between mb-6">
                    <div>
                        <h1 className="text-2xl font-extrabold text-text-primary">{project?.name || 'Project Workspace'}</h1>
                        <div className="flex items-center gap-3 mt-1.5">
                            <span className={`px-2.5 py-0.5 rounded-full text-xs font-bold ${project?.status === 'active' ? 'bg-success/10 text-success' :
                                    project?.status === 'completed' ? 'bg-info/10 text-info' :
                                        'bg-warning/10 text-warning'
                                }`}>{project?.status || 'active'}</span>
                            <span className="text-text-tertiary text-xs">Phase: <strong className="text-text-secondary capitalize">{project?.phase || 'planning'}</strong></span>
                        </div>
                    </div>
                    <div className="text-right">
                        <p className="text-[10px] font-bold text-text-tertiary uppercase">Total Budget</p>
                        <p className="text-xl font-bold text-text-primary">{formatCurrency(project?.totalBudget)}</p>
                    </div>
                </div>

                {/* Tabs */}
                <div className="flex gap-1 border-b border-border-light mb-6 overflow-x-auto">
                    {TABS.map(t => {
                        const Icon = t.icon;
                        return (
                            <button key={t.key} onClick={() => setTab(t.key)}
                                className={`flex items-center gap-2 px-4 py-2.5 text-sm font-bold border-b-2 transition-all whitespace-nowrap ${tab === t.key ? 'border-primary text-primary' : 'border-transparent text-text-secondary hover:text-text-primary'
                                    }`}>
                                <Icon size={15} /> {t.label}
                            </button>
                        );
                    })}
                </div>

                {/* Tab Content */}
                <div className="bg-surface border border-border-light rounded-2xl p-6 shadow-sm">

                    {/* Overview */}
                    {tab === 'overview' && (
                        <div className="space-y-6">
                            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                                {[
                                    ['Total Budget', formatCurrency(project?.totalBudget), DollarSign, 'primary'],
                                    ['Deployed', formatCurrency(project?.deployedBudget), Check, 'success'],
                                    ['Milestones', `${milestones.filter(m => m.status === 'completed').length}/${milestones.length}`, Milestone, 'info'],
                                    ['Team', String((project?.investors?.length || 0) + 2), Users, 'warning'],
                                ].map(([label, value, Icon, color]) => (
                                    <div key={label} className={`bg-${color}/5 border border-${color}/10 rounded-xl p-4`}>
                                        <Icon size={18} className={`text-${color} mb-2`} />
                                        <p className="text-xs text-text-tertiary font-bold uppercase">{label}</p>
                                        <p className="text-xl font-bold text-text-primary">{value}</p>
                                    </div>
                                ))}
                            </div>

                            {/* Quick milestone view */}
                            <div>
                                <h3 className="text-sm font-bold text-text-primary mb-3">Phase Progress</h3>
                                {milestones.length === 0 ? (
                                    <div className="bg-surface-element rounded-lg px-4 py-3 text-xs text-text-secondary">
                                        No milestone progress recorded yet.
                                    </div>
                                ) : (
                                    <div className="flex items-center gap-2 overflow-x-auto pb-1">
                                        {milestones.map((milestone, index) => (
                                            <React.Fragment key={`${milestone.label}-${index}`}>
                                                <div className={`flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-bold whitespace-nowrap ${milestone.status === 'completed' ? 'bg-success/10 text-success' :
                                                        milestone.status === 'in-progress' ? 'bg-primary/10 text-primary ring-1 ring-primary/20' :
                                                            'bg-surface-element text-text-tertiary'
                                                    }`}>
                                                    {milestone.status === 'completed' ? <Check size={12} /> : milestone.status === 'in-progress' ? <Clock size={12} /> : null}
                                                    {milestone.label}
                                                </div>
                                                {index < milestones.length - 1 && <ChevronRight size={14} className="text-text-tertiary" />}
                                            </React.Fragment>
                                        ))}
                                    </div>
                                )}
                            </div>
                        </div>
                    )}

                    {/* Milestones */}
                    {tab === 'milestones' && (
                        <div className="space-y-4">
                            <div className="flex items-center justify-between mb-2">
                                <h3 className="text-sm font-bold text-text-primary">Project Milestones</h3>
                            </div>
                            {milestones.length === 0 ? (
                                <div className="text-sm text-text-secondary bg-surface-element rounded-lg p-4">
                                    No milestones have been added to this project.
                                </div>
                            ) : milestones.map((ms, i) => (
                                <div key={i} className={`border rounded-xl p-4 transition-all ${ms.status === 'completed' ? 'border-success/20 bg-success/3' :
                                        ms.status === 'in-progress' ? 'border-primary/20 bg-primary/3' :
                                            'border-border-light'
                                    }`}>
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-3">
                                            <div className={`w-8 h-8 rounded-full flex items-center justify-center ${ms.status === 'completed' ? 'bg-success text-white' :
                                                    ms.status === 'in-progress' ? 'bg-primary text-white' :
                                                        'bg-surface-element text-text-tertiary'
                                                }`}>
                                                {ms.status === 'completed' ? <Check size={14} /> : <span className="text-xs font-bold">{i + 1}</span>}
                                            </div>
                                            <div>
                                                <p className="text-sm font-bold text-text-primary">{ms.label}</p>
                                                <p className="text-xs text-text-secondary capitalize">{ms.status}</p>
                                            </div>
                                        </div>
                                        {ms.budget > 0 && (
                                            <div className="text-right">
                                                <p className="text-xs text-text-tertiary">Budget</p>
                                                <p className="text-sm font-bold text-text-primary">{formatCurrency(ms.budget)}</p>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}

                    {/* Equity Ledger */}
                    {tab === 'equity' && (
                        <div className="space-y-6">
                            <h3 className="text-sm font-bold text-text-primary">Equity Distribution</h3>
                            {equityData.length === 0 ? (
                                <div className="text-sm text-text-secondary bg-surface-element rounded-lg p-4">
                                    Equity ledger entries are not available for this project yet.
                                </div>
                            ) : (
                                <>
                                    <div className="flex items-center gap-2 h-8 rounded-full overflow-hidden">
                                        {equityData.map((e, index) => (
                                            <div key={`${e.party || 'Party'}-${index}`} style={{ width: `${e.pct || 0}%`, backgroundColor: e.color || '#94a3b8' }}
                                                className="h-full flex items-center justify-center text-white text-[10px] font-bold min-w-[30px]">
                                                {e.pct || 0}%
                                            </div>
                                        ))}
                                    </div>
                                    <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
                                        {equityData.map((e, index) => (
                                            <div key={`${e.party || 'Party'}-${index}`} className="bg-surface-element rounded-xl p-4">
                                                <div className="flex items-center gap-2 mb-2">
                                                    <div className="w-3 h-3 rounded-full" style={{ backgroundColor: e.color || '#94a3b8' }} />
                                                    <p className="text-xs font-bold text-text-secondary">{e.party || `Party ${index + 1}`}</p>
                                                </div>
                                                <p className="text-2xl font-bold text-text-primary">{e.pct || 0}%</p>
                                                <p className={`text-[10px] font-bold mt-1 ${e.vested ? 'text-success' : 'text-warning'}`}>
                                                    {e.vested ? '✓ Fully Vested' : '○ Vesting'}
                                                </p>
                                            </div>
                                        ))}
                                    </div>
                                    <div className="bg-info/5 border border-info/10 rounded-xl p-4 text-xs text-text-secondary">
                                        <strong>Realtor equity</strong> is carried equity with vesting conditions tied to project completion. Distribution records and payment logs are stored with traceable transaction IDs.
                                    </div>
                                </>
                            )}
                        </div>
                    )}

                    {/* Documents */}
                    {tab === 'documents' && (
                        <div className="space-y-4">
                            <div className="flex items-center justify-between">
                                <h3 className="text-sm font-bold text-text-primary">Project Documents</h3>
                                <button className="btn btn-primary text-xs px-4 py-2 flex items-center gap-1.5"><Upload size={13} /> Upload</button>
                            </div>
                            {projectDocuments.length === 0 ? (
                                <div className="text-sm text-text-secondary bg-surface-element rounded-lg p-4">
                                    No project documents uploaded yet.
                                </div>
                            ) : projectDocuments.map((documentItem, index) => (
                                <div key={`${documentItem.name || 'Document'}-${index}`} className="flex items-center justify-between p-4 border border-border-light rounded-xl hover:bg-surface-hover transition-all">
                                    <div className="flex items-center gap-3">
                                        <FileText size={18} className="text-primary" />
                                        <div>
                                            <p className="text-sm font-bold text-text-primary">{documentItem.name || `Document ${index + 1}`}</p>
                                            <p className="text-[10px] text-text-tertiary">{documentItem.version || 'v1.0'} · {documentItem.uploadedAt || 'Uploaded recently'}</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${documentItem.status === 'signed' ? 'bg-success/10 text-success' : 'bg-info/10 text-info'}`}>
                                            {documentItem.status || 'uploaded'}
                                        </span>
                                        <button className="p-1.5 rounded-lg hover:bg-surface-element"><Download size={14} className="text-text-secondary" /></button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}

                    {/* Messages */}
                    {tab === 'messages' && (
                        <div className="space-y-4">
                            <h3 className="text-sm font-bold text-text-primary">Project Messages</h3>
                            <div className="bg-warning/5 border border-warning/10 rounded-xl p-3 text-[11px] text-warning font-medium">
                                ⚠ All communication must occur within AnchorPlot. Sharing external contact information is prohibited.
                            </div>
                            <div className="h-64 overflow-y-auto border border-border-light rounded-xl p-4 space-y-3 bg-surface-element/30">
                                {messages.length === 0 && (
                                    <p className="text-center text-text-tertiary text-sm py-8">No messages yet. Start the conversation.</p>
                                )}
                                {messages.map((msg, i) => (
                                    <div key={i} className={`flex ${msg.senderId === userData?.uid ? 'justify-end' : 'justify-start'}`}>
                                        <div className={`max-w-[70%] rounded-xl p-3 ${msg.senderId === userData?.uid ? 'bg-primary text-white' : 'bg-surface border border-border-light'
                                            }`}>
                                            <p className={`text-[10px] font-bold mb-1 ${msg.senderId === userData?.uid ? 'text-white/70' : 'text-text-tertiary'}`}>{msg.senderName}</p>
                                            <p className="text-sm">{msg.text}</p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                            <div className="flex gap-2">
                                <input type="text" value={newMessage} onChange={e => setNewMessage(e.target.value)}
                                    onKeyDown={e => e.key === 'Enter' && handleSendMessage()}
                                    placeholder="Type a message..."
                                    className="flex-1 bg-surface border border-border-light rounded-xl py-2.5 px-4 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary" />
                                <button onClick={handleSendMessage}
                                    className="btn btn-primary px-4 py-2.5 flex items-center gap-1.5 text-sm"><Send size={14} /> Send</button>
                            </div>
                        </div>
                    )}

                    {/* Compliance */}
                    {tab === 'compliance' && (
                        <div className="space-y-4">
                            <h3 className="text-sm font-bold text-text-primary">Compliance Checkpoints</h3>
                            {complianceCheckpoints.length === 0 ? (
                                <div className="text-sm text-text-secondary bg-surface-element rounded-lg p-4">
                                    No compliance checkpoints defined for this project yet.
                                </div>
                            ) : complianceCheckpoints.map((cp, i) => (
                                <div key={i} className={`flex items-center gap-4 p-4 rounded-xl border ${cp.status === 'complete' ? 'border-success/15 bg-success/3' : 'border-border-light'
                                    }`}>
                                    <div className={`w-7 h-7 rounded-full flex items-center justify-center ${cp.status === 'complete' ? 'bg-success text-white' : 'bg-surface-element text-text-tertiary'
                                        }`}>
                                        {cp.status === 'complete' ? <Check size={13} /> : <Clock size={13} />}
                                    </div>
                                    <div className="flex-1">
                                        <p className="text-sm font-bold text-text-primary">{cp.label}</p>
                                        {cp.date && <p className="text-[10px] text-text-tertiary">{cp.date}</p>}
                                    </div>
                                    <span className={`px-2.5 py-0.5 rounded-full text-[10px] font-bold ${cp.status === 'complete' ? 'bg-success/10 text-success' : 'bg-warning/10 text-warning'
                                        }`}>{cp.status}</span>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import {
    Home, DollarSign, Users, Wrench, FileText, Check, Clock, AlertCircle,
    Building2, TrendingUp, Plus, ChevronRight, Shield
} from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import PageHeader from '../components/PageHeader';
import { getPropertiesForUser } from '../services/dashboardData';

export default function PropertyManagement() {
    const { userData } = useAuth();
    const [properties, setProperties] = useState([]);
    const [selectedProperty, setSelectedProperty] = useState(null);
    const [loading, setLoading] = useState(true);
    const [tab, setTab] = useState('overview');

    useEffect(() => {
        const fetchProperties = async () => {
            if (!userData?.uid) {
                setProperties([]);
                setSelectedProperty(null);
                setLoading(false);
                return;
            }
            try {
                const scopedProperties = await getPropertiesForUser(userData);
                const propsData = scopedProperties.map(data => {
                    const units = Number(data.units ?? data.existingUnits) || 0;
                    const occupied = Number(data.occupied) || 0;
                    // Provide safe defaults for missing arrays/numbers to avoid crashes
                    return {
                        id: data.id,
                        name: data.name || 'Unnamed Property',
                        address: data.address || data.fullAddress || 'Address unlisted',
                        units,
                        occupied,
                        vacancyRate: units ? (((units - occupied) / units) * 100).toFixed(1) : 0,
                        monthlyRevenue: Number(data.monthlyRevenue) || 0,
                        status: data.status || 'unknown',
                        manager: data.managerName || 'Owner Managed',
                        affordable: Boolean(data.affordable || data.affordableHousingOptIn),
                        affordableUnits: Number(data.affordableUnits) || 0,
                        maintenance: Array.isArray(data.maintenance) ? data.maintenance : [],
                        rentRoll: Array.isArray(data.rentRoll) ? data.rentRoll : [],
                        complianceRequirements: Array.isArray(data.complianceRequirements) ? data.complianceRequirements : [],
                    };
                });

                setProperties(propsData);
                setSelectedProperty(propsData.length > 0 ? propsData[0] : null);
            } catch (error) {
                console.error('Error fetching managed properties:', error);
                setProperties([]);
                setSelectedProperty(null);
            } finally {
                setLoading(false);
            }
        };

        fetchProperties();
    }, [userData]);

    const prop = selectedProperty;
    const occupancyPercent = prop?.units ? Math.round((prop.occupied / prop.units) * 100) : 0;
    const affordabilityPercent = prop?.units ? Math.round((prop.affordableUnits / prop.units) * 100) : 0;
    const complianceItems = prop?.complianceRequirements?.length
        ? prop.complianceRequirements
        : [
            { label: 'Annual Income Verification', due: 'TBD', status: 'upcoming' },
            { label: 'Rent Reasonableness Review', due: 'TBD', status: 'upcoming' },
            { label: 'City Compliance Report', due: 'TBD', status: 'upcoming' },
        ];

    if (loading) {
        return (
            <div className="h-full flex items-center justify-center text-text-secondary">
                Loading property dashboard...
            </div>
        );
    }

    if (!prop) {
        return (
            <div className="h-full overflow-y-auto p-6 lg:p-8">
                <PageHeader title="Property Management" subtitle="Manage stabilized properties, rent rolls, maintenance and compliance reporting." />
                <div className="bg-surface border border-border-light rounded-2xl p-12 text-center text-text-secondary mt-12 shadow-sm">
                    <Building2 size={48} className="mx-auto mb-4 text-text-tertiary" />
                    <h3 className="text-xl font-bold text-text-primary mb-2">No Properties Found</h3>
                    <p>You don't have any properties currently assigned for management.</p>
                </div>
            </div>
        );
    }

    return (
        <div className="h-full overflow-y-auto">
            <div className="max-w-5xl mx-auto p-6 lg:p-8">
                <PageHeader title="Property Management" subtitle="Manage stabilized properties, rent rolls, maintenance and compliance reporting." />

                {/* Property Selector */}
                <div className="flex gap-3 mb-6 overflow-x-auto">
                    {properties.map(p => (
                        <button key={p.id} onClick={() => setSelectedProperty(p)}
                            className={`flex items-center gap-3 px-4 py-3 rounded-xl border whitespace-nowrap transition-all ${selectedProperty?.id === p.id ? 'border-primary bg-primary/5 shadow-sm' : 'border-border-light bg-surface hover:bg-surface-hover'
                                }`}>
                            <Building2 size={18} className={selectedProperty?.id === p.id ? 'text-primary' : 'text-text-tertiary'} />
                            <div className="text-left">
                                <p className={`text-sm font-bold ${selectedProperty?.id === p.id ? 'text-primary' : 'text-text-primary'}`}>{p.name}</p>
                                <p className="text-[10px] text-text-tertiary">{p.units} units</p>
                            </div>
                        </button>
                    ))}
                </div>

                {/* Stats */}
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
                    {[
                        ['Units', `${prop.occupied}/${prop.units}`, Users, 'primary'],
                        ['Vacancy', `${prop.vacancyRate}%`, Home, prop.vacancyRate > 10 ? 'danger' : 'success'],
                        ['Revenue', `$${prop.monthlyRevenue.toLocaleString()}/mo`, DollarSign, 'info'],
                        ['Maintenance', String(prop.maintenance.length), Wrench, 'warning'],
                    ].map(([label, value, Icon, color]) => (
                        <div key={label} className={`bg-${color}/5 border border-${color}/10 rounded-xl p-4`}>
                            <Icon size={18} className={`text-${color} mb-2`} />
                            <p className="text-xs text-text-tertiary font-bold uppercase">{label}</p>
                            <p className="text-xl font-bold text-text-primary">{value}</p>
                        </div>
                    ))}
                </div>

                {/* Tabs */}
                <div className="flex gap-1 border-b border-border-light mb-6">
                    {[['overview', 'Overview'], ['rentroll', 'Rent Roll'], ['maintenance', 'Maintenance'], ['compliance', 'Compliance']].map(([key, label]) => (
                        <button key={key} onClick={() => setTab(key)}
                            className={`px-5 py-2.5 text-sm font-bold border-b-2 transition-all ${tab === key ? 'border-primary text-primary' : 'border-transparent text-text-secondary hover:text-text-primary'
                                }`}>
                            {label}
                        </button>
                    ))}
                </div>

                <div className="bg-surface border border-border-light rounded-2xl p-6 shadow-sm">

                    {/* Overview Tab */}
                    {tab === 'overview' && (
                        <div className="space-y-5">
                            <div className="grid grid-cols-2 gap-4">
                                {[
                                    ['Property', prop.name],
                                    ['Address', prop.address],
                                    ['Manager', prop.manager],
                                    ['Status', prop.status],
                                ].map(([k, v]) => (
                                    <div key={k} className="bg-surface-element/50 rounded-lg p-3">
                                        <p className="text-[10px] font-bold text-text-tertiary uppercase">{k}</p>
                                        <p className="text-sm font-semibold text-text-primary mt-0.5 capitalize">{v}</p>
                                    </div>
                                ))}
                            </div>
                            {prop.affordable && (
                                <div className="bg-success/5 border border-success/10 rounded-xl p-4">
                                    <p className="text-xs font-bold text-success mb-1">♥ Affordable Housing Units</p>
                                    <p className="text-xs text-text-secondary">{prop.affordableUnits} of {prop.units} units are designated affordable. Compliance reporting is active.</p>
                                </div>
                            )}
                            {/* Occupancy bar */}
                            <div>
                                <div className="flex justify-between text-xs text-text-tertiary mb-1">
                                    <span>Occupancy Rate</span>
                                    <span>{occupancyPercent}%</span>
                                </div>
                                <div className="h-2.5 bg-surface-element rounded-full overflow-hidden">
                                    <div className="h-full bg-gradient-to-r from-primary to-success rounded-full" style={{ width: `${occupancyPercent}%` }} />
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Rent Roll Tab */}
                    {tab === 'rentroll' && (
                        <div>
                            <h3 className="text-sm font-bold text-text-primary mb-4">Unit Rent Roll</h3>
                            <div className="overflow-x-auto">
                                <table className="w-full text-sm">
                                    <thead>
                                        <tr className="border-b border-border-light">
                                            <th className="text-left p-3 text-xs font-bold text-text-tertiary uppercase">Unit</th>
                                            <th className="text-left p-3 text-xs font-bold text-text-tertiary uppercase">Tenant</th>
                                            <th className="text-left p-3 text-xs font-bold text-text-tertiary uppercase">Type</th>
                                            <th className="text-right p-3 text-xs font-bold text-text-tertiary uppercase">Rent</th>
                                            <th className="text-right p-3 text-xs font-bold text-text-tertiary uppercase">Lease End</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {prop.rentRoll.map((row, i) => (
                                            <tr key={i} className="border-b border-border-light last:border-0 hover:bg-surface-hover transition-colors">
                                                <td className="p-3 font-bold text-text-primary">{row.unit}</td>
                                                <td className="p-3 text-text-secondary">{row.tenant}</td>
                                                <td className="p-3">
                                                    <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${row.type === 'affordable' ? 'bg-success/10 text-success' : 'bg-surface-element text-text-tertiary'
                                                        }`}>{row.type}</span>
                                                </td>
                                                <td className="p-3 text-right font-semibold text-text-primary">{row.rent ? `$${row.rent.toLocaleString()}` : '—'}</td>
                                                <td className="p-3 text-right text-text-secondary">{row.lease}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    )}

                    {/* Maintenance Tab */}
                    {tab === 'maintenance' && (
                        <div className="space-y-4">
                            <div className="flex items-center justify-between">
                                <h3 className="text-sm font-bold text-text-primary">Maintenance Log</h3>
                                <button className="btn btn-primary text-xs px-4 py-2 flex items-center gap-1.5"><Plus size={13} /> New Request</button>
                            </div>
                            {prop.maintenance.map(m => (
                                <div key={m.id} className={`flex items-center gap-4 p-4 rounded-xl border ${m.priority === 'high' ? 'border-danger/15 bg-danger/3' : 'border-border-light'
                                    }`}>
                                    <div className={`w-8 h-8 rounded-full flex items-center justify-center ${m.status === 'in_progress' ? 'bg-warning/10 text-warning' :
                                        m.status === 'completed' ? 'bg-success/10 text-success' :
                                            'bg-surface-element text-text-tertiary'
                                        }`}>
                                        {m.status === 'completed' ? <Check size={14} /> : <Wrench size={14} />}
                                    </div>
                                    <div className="flex-1">
                                        <p className="text-sm font-bold text-text-primary">{m.title}</p>
                                        <p className="text-[10px] text-text-tertiary">{m.date} · Priority: {m.priority}</p>
                                    </div>
                                    <span className={`px-2.5 py-0.5 rounded-full text-[10px] font-bold capitalize ${m.status === 'in_progress' ? 'bg-warning/10 text-warning' :
                                        m.status === 'completed' ? 'bg-success/10 text-success' :
                                            'bg-info/10 text-info'
                                        }`}>{m.status.replace('_', ' ')}</span>
                                </div>
                            ))}
                        </div>
                    )}

                    {/* Compliance Tab */}
                    {tab === 'compliance' && (
                        <div className="space-y-4">
                            <h3 className="text-sm font-bold text-text-primary">Affordable Housing Compliance</h3>
                            {prop.affordable ? (
                                <div className="space-y-3">
                                    <div className="grid grid-cols-2 gap-3">
                                        {[
                                            ['Affordable Units', String(prop.affordableUnits)],
                                            ['Total Units', String(prop.units)],
                                            ['Affordability %', `${affordabilityPercent}%`],
                                            ['Status', 'Compliant'],
                                        ].map(([k, v]) => (
                                            <div key={k} className="bg-surface-element rounded-lg p-3">
                                                <p className="text-[9px] font-bold text-text-tertiary uppercase">{k}</p>
                                                <p className="text-sm font-bold text-text-primary mt-0.5">{v}</p>
                                            </div>
                                        ))}
                                    </div>
                                    <div className="space-y-2 mt-4">
                                        {complianceItems.map((r, i) => (
                                            <div key={i} className="flex items-center justify-between p-3 rounded-lg border border-border-light">
                                                <div className="flex items-center gap-2">
                                                    <Shield size={14} className="text-primary" />
                                                    <span className="text-xs font-medium text-text-primary">{r.label}</span>
                                                </div>
                                                <div className="flex items-center gap-2">
                                                    <span className="text-[10px] text-text-tertiary">Due: {r.due || 'TBD'}</span>
                                                    <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${r.status === 'complete' ? 'bg-success/10 text-success' : 'bg-info/10 text-info'}`}>
                                                        {r.status || 'upcoming'}
                                                    </span>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            ) : (
                                <div className="text-center py-8 text-text-tertiary">
                                    <Shield size={32} className="mx-auto mb-2" />
                                    <p className="text-sm">No affordable housing compliance requirements for this property.</p>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Users, DollarSign, Building2, TrendingUp, Check, ChevronRight, ArrowUpRight, Link, PieChart } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import PageHeader from '../components/PageHeader';

import { collection, query, where, getDocs } from 'firebase/firestore';
import { db } from '../services/firebase';

export default function RealtorManagement() {
    const { userData } = useAuth();
    const [referrals, setReferrals] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchReferrals = async () => {
            if (!userData?.uid) return;
            try {
                // Fetch projects where this user is the referring realtor
                const q = query(collection(db, 'projects'), where('realtorId', '==', userData.uid));
                const snapshot = await getDocs(q);

                // Map the project data to the referral view format
                const refsData = snapshot.docs.map(doc => {
                    const data = doc.data();
                    // Find the realtor's equity in the ledger if it exists
                    const realtorEquity = (data.equityLedger || []).find(e => e.party === 'Realtor' || e.realtorId === userData.uid);

                    return {
                        id: doc.id,
                        projectName: data.name || 'Unnamed Project',
                        ownerName: data.ownerName || 'Property Owner',
                        propertyCity: data.propertyCity || 'Unknown City',
                        status: data.status || 'active',
                        carriedEquity: realtorEquity ? realtorEquity.pct : (data.realtorCarriedEquity || 0),
                        vested: data.realtorVested || false,
                        vestingCondition: data.realtorVestingCondition || 'Project completion',
                        estimatedValue: data.realtorEstimatedValue || 0,
                        paidOut: data.realtorPaidOut || 0
                    };
                });
                setReferrals(refsData);
            } catch (error) {
                console.error('Error fetching referrals:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchReferrals();
    }, [userData]);

    const totalEstimated = referrals.reduce((sum, r) => sum + r.estimatedValue, 0);
    const totalPaid = referrals.reduce((sum, r) => sum + (r.paidOut || 0), 0);
    const activeReferrals = referrals.filter(r => r.status === 'active').length;

    return (
        <div className="h-full overflow-y-auto">
            <div className="max-w-5xl mx-auto p-6 lg:p-8">
                <PageHeader title="Referrals & Equity" subtitle="Track your property referrals and carried equity positions." />

                {/* Stats */}
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
                    {[
                        ['Total Referrals', String(referrals.length), Users, 'primary'],
                        ['Active', String(activeReferrals), Building2, 'success'],
                        ['Est. Total Value', `$${totalEstimated.toLocaleString()}`, TrendingUp, 'info'],
                        ['Paid Out', `$${totalPaid.toLocaleString()}`, DollarSign, 'warning'],
                    ].map(([label, value, Icon, color]) => (
                        <div key={label} className={`bg-${color}/5 border border-${color}/10 rounded-xl p-4`}>
                            <Icon size={18} className={`text-${color} mb-2`} />
                            <p className="text-xs text-text-tertiary font-bold uppercase">{label}</p>
                            <p className="text-xl font-bold text-text-primary">{value}</p>
                        </div>
                    ))}
                </div>

                {/* Info banner */}
                <div className="bg-warning/5 border border-warning/10 rounded-xl p-4 mb-6 text-xs text-text-secondary">
                    <strong className="text-warning">Carried Equity:</strong> Realtor carried equity is defined per project and can vary by deal, subject to vesting conditions tied to project milestones. Equity is tracked in the project's immutable equity ledger.
                </div>

                {/* Referral Cards */}
                <div className="space-y-4">
                    {referrals.map(ref => (
                        <div key={ref.id} className="bg-surface border border-border-light rounded-2xl p-5 shadow-sm">
                            <div className="flex items-start justify-between mb-3">
                                <div>
                                    <h3 className="text-sm font-bold text-text-primary">{ref.projectName}</h3>
                                    <p className="text-xs text-text-secondary">Referred by {ref.ownerName} · {ref.propertyCity}</p>
                                </div>
                                <span className={`px-2.5 py-0.5 rounded-full text-xs font-bold ${ref.status === 'completed' ? 'bg-success/10 text-success' : 'bg-primary/10 text-primary'
                                    }`}>{ref.status}</span>
                            </div>
                            <div className="grid grid-cols-4 gap-3">
                                <div className="bg-surface-element/50 rounded-lg p-3">
                                    <p className="text-[9px] font-bold text-text-tertiary uppercase">Carried Equity</p>
                                    <p className="text-lg font-bold text-text-primary">{ref.carriedEquity}%</p>
                                </div>
                                <div className="bg-surface-element/50 rounded-lg p-3">
                                    <p className="text-[9px] font-bold text-text-tertiary uppercase">Est. Value</p>
                                    <p className="text-sm font-bold text-text-primary">${ref.estimatedValue.toLocaleString()}</p>
                                </div>
                                <div className="bg-surface-element/50 rounded-lg p-3">
                                    <p className="text-[9px] font-bold text-text-tertiary uppercase">Vested</p>
                                    <p className={`text-sm font-bold ${ref.vested ? 'text-success' : 'text-warning'}`}>
                                        {ref.vested ? '✓ Yes' : '○ Pending'}
                                    </p>
                                </div>
                                <div className="bg-surface-element/50 rounded-lg p-3">
                                    <p className="text-[9px] font-bold text-text-tertiary uppercase">Condition</p>
                                    <p className="text-xs font-semibold text-text-primary">{ref.vestingCondition}</p>
                                </div>
                            </div>
                            {ref.paidOut > 0 && (
                                <div className="mt-3 flex items-center gap-2 text-xs text-success font-bold">
                                    <Check size={12} /> Paid out: ${ref.paidOut.toLocaleString()}
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
}

// src/services/firebase.js
import { initializeApp } from "firebase/app";
import { getAuth } from "firebase/auth";
import { getFirestore } from "firebase/firestore";
import { getStorage } from "firebase/storage";
import { getAnalytics } from "firebase/analytics";

// Firebase configuration - ALL values must come from environment variables
const firebaseConfig = {
    apiKey: import.meta.env.VITE_FIREBASE_API_KEY,
    authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
    projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID,
    storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET,
    messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
    appId: import.meta.env.VITE_FIREBASE_APP_ID,
    measurementId: import.meta.env.VITE_FIREBASE_MEASUREMENT_ID
};

// Validate that all required config values are present
const requiredConfigKeys = ['apiKey', 'authDomain', 'projectId', 'storageBucket', 'messagingSenderId', 'appId'];
const missingKeys = requiredConfigKeys.filter(key => !firebaseConfig[key]);

if (missingKeys.length > 0) {
    console.error('Missing Firebase configuration keys:', missingKeys);
    console.error('Please set the following environment variables in your .env file:');
    missingKeys.forEach(key => {
        const envKey = `VITE_FIREBASE_${key.replace(/([A-Z])/g, '_$1').toUpperCase()}`;
        console.error(`- ${envKey}`);
    });
    throw new Error('Firebase configuration is incomplete. Check console for details.');
}

// Initialize Firebase
const app = initializeApp(firebaseConfig);

let analytics = null;
if (typeof window !== 'undefined' && import.meta.env.PROD) {
    analytics = getAnalytics(app);
}

// Initialize Firebase services
export const auth = getAuth(app);
export const db = getFirestore(app);
export const storage = getStorage(app);

export default app;

/**
 * AnchorPlot Firestore Service Layer
 * Provides CRUD operations for all collections.
 */
import {
    collection, doc, getDoc, getDocs, addDoc, setDoc, updateDoc, deleteDoc,
    query, where, orderBy, limit, onSnapshot, serverTimestamp, arrayUnion, arrayRemove, increment
} from 'firebase/firestore';
import { db } from './firebase';
import { getMatchScore } from './matchScore';

// ================================
//  USERS
// ================================
export const usersRef = collection(db, 'users');

export async function getUser(uid) {
    const snap = await getDoc(doc(db, 'users', uid));
    return snap.exists() ? { id: snap.id, ...snap.data() } : null;
}

export async function updateUser(uid, data) {
    return updateDoc(doc(db, 'users', uid), { ...data, updatedAt: serverTimestamp() });
}

export async function listUsers(filters = {}) {
    let q = usersRef;
    if (filters.role) q = query(q, where('role', '==', filters.role));
    if (filters.kycStatus) q = query(q, where('kycStatus', '==', filters.kycStatus));
    const snap = await getDocs(q);
    return snap.docs.map(d => ({ id: d.id, ...d.data() }));
}

// ================================
//  PARCELS (Canonical Land Record)
// ================================
export const parcelsRef = collection(db, 'parcels');

export async function createParcel(data) {
    return addDoc(parcelsRef, {
        ...data,
        createdAt: serverTimestamp(),
        updatedAt: serverTimestamp(),
    });
}

export async function getParcel(id) {
    const snap = await getDoc(doc(db, 'parcels', id));
    return snap.exists() ? { id: snap.id, ...snap.data() } : null;
}

export async function listParcels(filters = {}) {
    let q = parcelsRef;
    if (filters.ownerUid) q = query(q, where('ownerUid', '==', filters.ownerUid));
    if (filters.city) q = query(q, where('city', '==', filters.city));
    const snap = await getDocs(q);
    return snap.docs.map(d => ({ id: d.id, ...d.data() }));
}

export async function updateParcel(id, data) {
    return updateDoc(doc(db, 'parcels', id), { ...data, updatedAt: serverTimestamp() });
}

// ================================
//  LISTINGS (Market Opportunity)
// ================================
export const listingsRef = collection(db, 'listings');

export async function createListing(data) {
    const resolvedMatchScore = getMatchScore(data);

    return addDoc(listingsRef, {
        ...data,
        matchScore: resolvedMatchScore,
        status: data.status || 'pending_review',
        views: 0,
        pitches: [],
        createdAt: serverTimestamp(),
        updatedAt: serverTimestamp(),
    });
}

export async function getListing(id) {
    const snap = await getDoc(doc(db, 'listings', id));
    return snap.exists() ? { id: snap.id, ...snap.data() } : null;
}

export async function listListings(filters = {}) {
    let q = listingsRef;
    if (filters.status) q = query(q, where('status', '==', filters.status));
    if (filters.parcelId) q = query(q, where('parcelId', '==', filters.parcelId));
    if (filters.city) q = query(q, where('city', '==', filters.city));
    const snap = await getDocs(q);
    return snap.docs.map(d => ({ id: d.id, ...d.data() }));
}

export async function updateListing(id, data) {
    return updateDoc(doc(db, 'listings', id), { ...data, updatedAt: serverTimestamp() });
}

export async function approveListing(id) {
    return updateListing(id, { status: 'approved' });
}

export async function rejectListing(id, reason = '') {
    return updateListing(id, { status: 'rejected', rejectionReason: reason });
}

export async function incrementListingViews(id) {
    return updateDoc(doc(db, 'listings', id), { views: increment(1) });
}

